UPDATE event.email_logs
SET
     status = 'failed'
    ,error_message = #{errorMessage}
WHERE email_log_seq = #{emailLogSeq}

UPDATE event.email_logs
SET
     status = 'failed'
    ,error_message = #{errorMessage}
    ,retry_count = COALESCE(retry_count, 0) + 1
WHERE email_log_seq = #{emailLogSeq}
